import{c as i,a0 as t,U as n,j as r,g as a,n as s,o as d,m as l}from"./chunks/framework.Dvkoa_vi.js";const T=JSON.parse('{"title":"Sesión 14: DataTable de extremo a extremo","description":"DataTable server-side con ClaseCrudUtils en .NET y vueua-datatable en Vue — paginación, filtros y ordenación","frontmatter":{"title":"Sesión 14: DataTable de extremo a extremo","description":"DataTable server-side con ClaseCrudUtils en .NET y vueua-datatable en Vue — paginación, filtros y ordenación","outline":"deep"},"headers":[],"relativePath":"04-integracion/sesiones/sesion-17-datatable/index.md","filePath":"04-integracion/sesiones/sesion-17-datatable/index.md"}'),c={name:"04-integracion/sesiones/sesion-17-datatable/index.md"};function p(u,e,b,m,v,h){const o=t("CopyOrDownloadAsMarkdownButtons");return n(),r("div",null,[e[0]||(e[0]=a("div",{style:{display:"none"},hidden:"true","aria-hidden":"true"},"Are you an LLM? You can read better optimized documentation at /curso-normalizacion/04-integracion/sesiones/sesion-17-datatable.md for this page in Markdown format",-1)),e[1]||(e[1]=a("h1",{id:"sesion-14-datatable-de-extremo-a-extremo",tabindex:"-1"},[s("Sesión 14: DataTable de extremo a extremo "),a("a",{class:"header-anchor",href:"#sesion-14-datatable-de-extremo-a-extremo","aria-label":"Permalink to “Sesión 14: DataTable de extremo a extremo”"},"​")],-1)),d(o),e[2]||(e[2]=l('<nav class="table-of-contents"><ul><li><a href="#objetivos">Objetivos</a></li><li><a href="#cuando-usar">14.1 Listado simple vs DataTable server-side</a></li><li><a href="#servidor">14.2 Lado servidor: ClaseCrudUtils</a></li><li><a href="#cliente">14.3 Lado cliente: vueua-datatable</a></li><li><a href="#conexion">14.4 Conectando las dos partes</a></li><li><a href="#tarea-pf">14.5 Tarea progresiva del proyecto final</a></li></ul></nav><div class="info custom-block"><p class="custom-block-title">CONTEXTO</p><p>Cuando una tabla tiene miles de registros, no podemos cargarlos todos en el cliente. En esta sesión construimos un DataTable server-side completo: desde el endpoint .NET con <code>ClaseCrudUtils</code> hasta el componente <code>vueua-datatable</code> en Vue, pasando por filtros, paginación y ordenación.</p></div><h2 id="objetivos" tabindex="-1">Objetivos <a class="header-anchor" href="#objetivos" aria-label="Permalink to “Objetivos”">​</a></h2><p>Al finalizar esta sesión, el alumno será capaz de:</p><ul><li>Decidir cuándo usar un listado simple y cuándo un DataTable server-side</li><li>Configurar <code>ClaseCrudUtils</code> y <code>CamposFiltros</code> en el servicio .NET</li><li>Implementar paginación, filtros y ordenación en el endpoint</li><li>Conectar el componente <code>vueua-datatable</code> de Vue con el endpoint</li><li>Tener un flujo completo funcionando de extremo a extremo</li></ul><h2 id="cuando-usar" tabindex="-1">14.1 Listado simple vs DataTable server-side <a class="header-anchor" href="#cuando-usar" aria-label="Permalink to “14.1 Listado simple vs DataTable server-side”">​</a></h2><div class="warning custom-block"><p class="custom-block-title">IMPORTANTE</p><p>El contenido detallado de esta sesión está pendiente de publicación.</p></div><p>Pendiente de publicación.</p><p>Material de referencia: <a href="./../../02-dotnet/sesiones/sesion-04-datatable-clasecrud/">DataTable server-side (.NET)</a></p><h2 id="servidor" tabindex="-1">14.2 Lado servidor: ClaseCrudUtils <a class="header-anchor" href="#servidor" aria-label="Permalink to “14.2 Lado servidor: ClaseCrudUtils”">​</a></h2><p>Pendiente de publicación.</p><h2 id="cliente" tabindex="-1">14.3 Lado cliente: vueua-datatable <a class="header-anchor" href="#cliente" aria-label="Permalink to “14.3 Lado cliente: vueua-datatable”">​</a></h2><p>Pendiente de publicación.</p><h2 id="conexion" tabindex="-1">14.4 Conectando las dos partes <a class="header-anchor" href="#conexion" aria-label="Permalink to “14.4 Conectando las dos partes”">​</a></h2><p>Pendiente de publicación.</p><h2 id="tarea-pf" tabindex="-1">14.5 Tarea progresiva del proyecto final <a class="header-anchor" href="#tarea-pf" aria-label="Permalink to “14.5 Tarea progresiva del proyecto final”">​</a></h2><div class="tip custom-block"><p class="custom-block-title">MÓDULO 2 · CIERRE DEL DATATABLE DE RECURSO + MÓDULO 4 · DISPONIBILIDAD</p><p><strong>Módulo 2 (<code>recurso-&lt;nombre&gt;</code>) — cierre:</strong></p><ul><li>DataTable server-side de <code>Recurso</code> con paginación, ordenación y filtros.</li><li><strong>Filtro desplegable</strong> por <code>TipoRecurso</code> (usando <code>vueua-autocomplete</code> o un <code>&lt;select&gt;</code> con los tipos cargados al <code>onMounted</code>).</li><li>Acciones por fila: editar, activar/desactivar, marcar mantenimiento, eliminar (con confirmación).</li><li>Botón &quot;Calendario&quot; en cada fila que aún no enlaza a nada — déjalo preparado para el módulo 4.</li></ul><p><strong>Módulo 4 (<code>reserva-&lt;nombre&gt;</code>) — arranque:</strong></p><ul><li>Endpoint <code>GET /api/Reservas/disponibilidad?recursoId=…&amp;fecha=…</code> que devuelve las franjas libres del día (consultando horario, festivos y reservas existentes).</li><li>Vista de lista de reservas del usuario actual con DataTable server-side filtrado por <code>CodPer = User.CodPer</code>.</li></ul><p>Mapa completo: <a href="./../../../06-proyecto-final/">Proyecto final del curso</a>.</p></div><hr><table tabindex="0"><thead><tr><th>Anterior</th><th>Inicio</th><th>Siguiente</th></tr></thead><tbody><tr><td><a href="./../../../04-integracion/sesiones/sesion-16-errores/">← Sesión 16: Gestión de errores de extremo a extremo</a></td><td><a href="./../../../">Índice del curso</a></td><td><a href="./../../../05-avanzadas/sesiones/sesion-18-internacionalizacion/">Sesión 18: Internacionalización →</a></td></tr></tbody></table>',19))])}const x=i(c,[["render",p]]);export{T as __pageData,x as default};
